    // Method to add products and their prices to the price list
    public void addProduct(String productName, int price) {
        priceList.put(productName, price);
    }

    // Method to split the order string and retrieve the product details
    public String[] getOrderDetails(String orderString) {
        return orderString.split("\\s+");
    }

    // Method to calculate the total price of the order
    public int calculateTotalPrice(String orderString) {
        String[] orderData = getOrderDetails(orderString);
        String[] productDetails = orderData[0].split("–");
        int productPrice = priceList.get(productDetails[1]);
        int orderPrice = Integer.parseInt(orderData[1]) * productPrice;
        return orderPrice;
    }

    public static void main(String[] args) {
        OrderProcessor processor = new OrderProcessor();

        // Add products and their prices
        processor.addProduct("Apple", 2.50);
        processor.addProduct("Banana", 1.75);

        // Example order string
        String orderString = "Apple–2–3";

        // Calculate the total price of the order
        int totalPrice = processor.calculateTotalPrice(orderString);

        System.out.println("Total Price: $" + totalPrice);
    }
}
```

